mapper.select:
SELECT s.id AS "id", s.register_id AS "registerId", s.department_id AS "departmentId", s.status AS "status", s.ai_escalation_enabled AS "aiEscalationEnabled", s.doctor_last_active_at AS "doctorLastActiveAt", s.creation_time AS "creationTime", r.real_name AS "realName", r.case_number AS "caseNumber", r.gender AS "gender", r.age AS "age", fp.priority_level AS "priorityLevel", ( SELECT COUNT(*) FROM follow_up_communication_message m WHERE m.session_id = s.id AND m.sender_type = 'patient' ) AS "patientMessageCount", ( SELECT m.content FROM follow_up_communication_message m WHERE m.session_id = s.id ORDER BY m.creation_time DESC, m.id DESC LIMIT 1 ) AS "lastMessagePreview", ( SELECT m.creation_time FROM follow_up_communication_message m WHERE m.session_id = s.id ORDER BY m.creation_time DESC, m.id DESC LIMIT 1 ) AS "lastMessageTime" FROM follow_up_communication_session s INNER JOIN register r ON r.id = s.register_id LEFT JOIN follow_up_patient_profile fp ON fp.register_id = s.register_id
s.department_id = #{departmentId}
ORDER BY "lastMessageTime" DESC NULLS LAST, s.id DESC

mapper.insert:
INSERT INTO follow_up_communication_session (
    register_id, department_id, status, ai_escalation_enabled, doctor_last_active_at
) VALUES (
    #{registerId}, #{departmentId}, COALESCE(#{status}, 'active'),
    COALESCE(#{aiEscalationEnabled}, 1), #{doctorLastActiveAt}
)

mapper.update:
UPDATE follow_up_communication_session
SET doctor_last_active_at = #{activeAt}
WHERE id = #{id}

UPDATE follow_up_communication_session
SET ai_escalation_enabled = #{enabled}
WHERE id = #{id}

mapper.insert:
INSERT INTO follow_up_communication_message (
    session_id, sender_type, message_type, content, summary_id, workflow_run_id
) VALUES (
    #{sessionId}, #{senderType}, COALESCE(#{messageType}, 'text'),
    #{content}, #{summaryId}, #{workflowRunId}
)

INSERT INTO follow_up_case_summary (
    register_id, session_id, ai_draft_content, ai_medical_advice, ai_risk_alerts,
    doctor_content, status, shared_to_patient, workflow_run_id, model_id
) VALUES (
    #{registerId}, #{sessionId}, #{aiDraftContent}, #{aiMedicalAdvice}, #{aiRiskAlerts},
    #{doctorContent}, COALESCE(#{status}, 'draft'), COALESCE(#{sharedToPatient}, 0),
    #{workflowRunId}, #{modelId}
)

mapper.update:
UPDATE follow_up_case_summary
SET doctor_content = #{doctorContent}
WHERE id = #{id}

UPDATE follow_up_case_summary
SET status = 'revoked', shared_to_patient = 0
WHERE id = #{id}

mapper.select:
SELECT metric_key AS "metricKey", metric_value AS "metricValue", unit AS "unit", record_date AS "recordDate"
FROM follow_up_health_metric
WHERE register_id = #{registerId}
  AND record_date BETWEEN #{from} AND #{to}
ORDER BY record_date DESC, metric_key ASC

SELECT id AS "id", schedule_date AS "scheduleDate", status AS "status"
FROM follow_up_day_schedule
WHERE register_id = #{registerId}
  AND schedule_date = #{date}
  AND item_type = 'interview'
LIMIT 1
